import { normalizeCandles } from '../../lce-core/src/index.mjs';
export function splitFormationHoldout(candles,ratio=.7){ const c=normalizeCandles(candles); const cut=Math.max(1,Math.min(c.length-1,Math.floor(c.length*ratio))); return {formation:c.slice(0,cut),holdout:c.slice(cut),cutTimeMs:c[cut]?.timeMs??null}; }
export function assertNoLookahead({zones,cutTimeMs}){ const violations=(zones||[]).filter(z=>{ const t=Date.parse(z.createdAt||0); return Number.isFinite(t)&&t>cutTimeMs; }); return {ok:violations.length===0,violations}; }
export function validateForwardTouches({zones,holdoutCandles,touchToleranceBps=12}){ const candles=normalizeCandles(holdoutCandles); const rows=(zones||[]).map(z=>{ const p=Number(z.price); const w=Math.max(p*touchToleranceBps/10000,1e-9); const touched=candles.some(c=>c.low<=p+w&&c.high>=p-w); return {id:z.id,symbol:z.symbol,side:z.side,price:p,strength:z.strength,touched,win:touched}; }); const touched=rows.filter(r=>r.touched).length; const wins=rows.filter(r=>r.win).length; return {rows,summary:{zones:rows.length,touched,wins,touchRatePct:rows.length?touched/rows.length*100:0,winRateAfterTouchPct:touched?wins/touched*100:0}}; }
